 func TestReviewSession_CreatePersistsManifest(t *testing.T) {
 	workDir := t.TempDir()
 	store := NewReviewSessionStore(workDir)

  1	package server
  2	
  3	import (
  4		"bufio"
  5		"encoding/json"
  6		"errors"
  7		"fmt"
  8		"os"
  9		"path/filepath"
 10		"strings"
 11		"sync"
 12		"time"
 13	)
 14	
 15	const (
 16		reviewSessionsDirName = "reviews"
 17		reviewManifestName    = "manifest.json"
 18		reviewTurnsName       = "turns.jsonl"
 19		reviewAttachmentsDir  = "attachments"
 20	)
 21	
 22	// ReviewSession is the server-side review state machine persisted under
 23	// .ddx/reviews/<session-id>/ for Story 16 and review mutations.
 24	//
 25	// Story 16 on-disk contract:
 26	//   - manifest.json stores the session metadata only: id, artifact refs,
 27	//     rubric/template/prompt refs, status, and billing limits.
 28	//   - turns.jsonl is append-only JSONL. Each non-empty line is one ReviewTurn
 29	//     record with actor, content, cost_usd, and created_at.
 30	//   - attachments/ stores any binary sidecar files for the session.
 31	//
 32	// The manifest is written when a session is created. Turns are appended
 33	// without rewriting prior lines so the review transcript remains durable and
 34	// streamable.
 35	type ReviewSession struct {
 36		ID             string       `json:"id"`
 37		ArtifactID     string       `json:"artifact_id"`
 38		ArtifactSHA    string       `json:"artifact_sha"`
 39		ArtifactGitRev string       `json:"artifact_git_rev"`
 40		SystemRubric   string       `json:"system_rubric"`
 41		TemplateRef    string       `json:"template_ref"`
 42		PromptRef      string       `json:"prompt_ref"`
 43		Status         string       `json:"status"`
 44		Turns          []ReviewTurn `json:"turns,omitempty"`
 45		CostUSD        float64      `json:"cost_usd"`
 46		MaxBillableUSD float64      `json:"max_billable_usd"`
 47	}
 48	
 49	// ReviewTurn is one append-only transcript entry in turns.jsonl.
 50	type ReviewTurn struct {
 51		Actor     string    `json:"actor"`
 52		Content   string    `json:"content"`
 53		CostUSD   float64   `json:"cost_usd"`
 54		CreatedAt time.Time `json:"created_at"`
 55	}
 56	
 57	type reviewSessionManifest struct {
 58		ID             string  `json:"id"`
 59		ArtifactID     string  `json:"artifact_id"`
 60		ArtifactSHA    string  `json:"artifact_sha"`
 61		ArtifactGitRev string  `json:"artifact_git_rev"`
 62		SystemRubric   string  `json:"system_rubric"`
 63		TemplateRef    string  `json:"template_ref"`
 64		PromptRef      string  `json:"prompt_ref"`
 65		Status         string  `json:"status"`
 66		CostUSD        float64 `json:"cost_usd"`
 67		MaxBillableUSD float64 `json:"max_billable_usd"`
 68	}
 69	
 70	// ReviewSessionStore persists review sessions under .ddx/reviews/.
 71	type ReviewSessionStore struct {
 72		projectRoot string
 73		mu          sync.Mutex
 74	}
 75	
 76	// NewReviewSessionStore constructs a store rooted at projectRoot.
 77	func NewReviewSessionStore(projectRoot string) *ReviewSessionStore {
 78		return &ReviewSessionStore{projectRoot: projectRoot}
 79	}
 80	
 81	// Create initializes the session directory, writes manifest.json, seeds
 82	// turns.jsonl, and creates attachments/.
 83	func (s *ReviewSessionStore) Create(session ReviewSession) error {
 84		if s == nil {
 85			return errors.New("review session store: nil store")
 86		}
 87		root, err := s.sessionRoot(session.ID)
 88		if err != nil {
 89			return err
 90		}
 91	
 92		s.mu.Lock()
 93		defer s.mu.Unlock()
 94	
 95		if err := os.MkdirAll(filepath.Join(root, reviewAttachmentsDir), 0o755); err != nil {
 96			return fmt.Errorf("review session: mkdir attachments: %w", err)
 97		}
 98		if err := writeJSONFile(filepath.Join(root, reviewManifestName), reviewSessionManifestFrom(session)); err != nil {
 99			return err
100		}
101		if err := os.WriteFile(filepath.Join(root, reviewTurnsName), nil, 0o644); err != nil {
102			return fmt.Errorf("review session: seed turns: %w", err)
103		}
104		return nil
105	}
106	
107	// AppendTurn appends a single transcript entry to turns.jsonl.
108	func (s *ReviewSessionStore) AppendTurn(sessionID string, turn ReviewTurn) error {
109		if s == nil {
110			return errors.New("review session store: nil store")
111		}
112		root, err := s.sessionRoot(sessionID)
113		if err != nil {
114			return err
115		}
116	
117		s.mu.Lock()
118		defer s.mu.Unlock()
119	
120		if err := os.MkdirAll(root, 0o755); err != nil {
121			return fmt.Errorf("review session: mkdir session: %w", err)
122		}
123		if turn.CreatedAt.IsZero() {
124			turn.CreatedAt = time.Now().UTC()
125		}
126		path := filepath.Join(root, reviewTurnsName)
127		f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
128		if err != nil {
129			return fmt.Errorf("review session: open turns: %w", err)
130		}
131		defer f.Close()
132		if err := json.NewEncoder(f).Encode(turn); err != nil {
133			return fmt.Errorf("review session: encode turn: %w", err)
134		}
135		return nil
136	}
137	
138	// Load reads the manifest plus append-only transcript back into memory.
139	func (s *ReviewSessionStore) Load(sessionID string) (*ReviewSession, error) {
140		if s == nil {
141			return nil, errors.New("review session store: nil store")
142		}
143		root, err := s.sessionRoot(sessionID)
144		if err != nil {
145			return nil, err
146		}
147	
148		data, err := os.ReadFile(filepath.Join(root, reviewManifestName))
149		if err != nil {
150			return nil, fmt.Errorf("review session: read manifest: %w", err)
151		}
152		var manifest reviewSessionManifest
153		if err := json.Unmarshal(data, &manifest); err != nil {
154			return nil, fmt.Errorf("review session: parse manifest: %w", err)
155		}
156		session := &ReviewSession{
157			ID:             manifest.ID,
158			ArtifactID:     manifest.ArtifactID,
159			ArtifactSHA:    manifest.ArtifactSHA,
160			ArtifactGitRev: manifest.ArtifactGitRev,
161			SystemRubric:   manifest.SystemRubric,
162			TemplateRef:    manifest.TemplateRef,
163			PromptRef:      manifest.PromptRef,
164			Status:         manifest.Status,
165			CostUSD:        manifest.CostUSD,
166			MaxBillableUSD: manifest.MaxBillableUSD,
167		}
168	
169		turnsPath := filepath.Join(root, reviewTurnsName)
170		f, err := os.Open(turnsPath)
171		if err != nil {
172			if os.IsNotExist(err) {
173				return session, nil
174			}
175			return nil, fmt.Errorf("review session: read turns: %w", err)
176		}
177		defer f.Close()
178	
179		scanner := bufio.NewScanner(f)
180		scanner.Buffer(make([]byte, 0, 64*1024), 8*1024*1024)
181		for scanner.Scan() {
182			line := strings.TrimSpace(scanner.Text())
183			if line == "" {
184				continue
185			}
186			var turn ReviewTurn
187			if err := json.Unmarshal([]byte(line), &turn); err != nil {
188				return nil, fmt.Errorf("review session: parse turn: %w", err)
189			}
190			session.Turns = append(session.Turns, turn)
191		}
192		if err := scanner.Err(); err != nil {
193			return nil, fmt.Errorf("review session: scan turns: %w", err)
194		}
195		return session, nil
196	}
197	
198	func (s *ReviewSessionStore) sessionRoot(sessionID string) (string, error) {
199		if s == nil {
200			return "", errors.New("review session store: nil store")
201		}
202		if s.projectRoot == "" {
203			return "", errors.New("review session store: empty project root")
204		}
205		if sessionID == "" {
206			return "", errors.New("review session store: empty session id")
207		}
208		if sessionID == "." || sessionID == ".." || strings.ContainsAny(sessionID, "/\\") {
209			return "", fmt.Errorf("review session store: invalid session id %q", sessionID)
210		}
211		return filepath.Join(s.projectRoot, ".ddx", reviewSessionsDirName, sessionID), nil
212	}
213	
214	func reviewSessionManifestFrom(session ReviewSession) reviewSessionManifest {
215		return reviewSessionManifest{
216			ID:             session.ID,
217			ArtifactID:     session.ArtifactID,
218			ArtifactSHA:    session.ArtifactSHA,
219			ArtifactGitRev: session.ArtifactGitRev,
220			SystemRubric:   session.SystemRubric,
221			TemplateRef:    session.TemplateRef,
222			PromptRef:      session.PromptRef,
223			Status:         session.Status,
224			CostUSD:        session.CostUSD,
225			MaxBillableUSD: session.MaxBillableUSD,
226		}
227	}
228	
229	func writeJSONFile(path string, v any) error {
230		data, err := json.MarshalIndent(v, "", "  ")
231		if err != nil {
232			return fmt.Errorf("review session: marshal %s: %w", path, err)
233		}
234		data = append(data, '\n')
235		if err := os.WriteFile(path, data, 0o644); err != nil {
236			return fmt.Errorf("review session: write %s: %w", path, err)
237		}
238		return nil
239	}

