 13	func TestReviewSession_CreatePersistsManifest(t *testing.T) {
 14		workDir := t.TempDir()
 15		store := NewReviewSessionStore(workDir)
 16		session := ReviewSession{
 17			ID:             "review-001",
 18			ArtifactID:     "art-123",
 19			ArtifactSHA:    "sha-abc",
 20			ArtifactGitRev: "gitrev-def",
 21			SystemRubric:   "rubric body",
 22			TemplateRef:    "template://review/default",
 23			PromptRef:      "prompt://review/default",
 24			Status:         "open",
 25			CostUSD:        1.25,
 26			MaxBillableUSD: 5.00,
 27		}
 28	
 29		if err := store.Create(session); err != nil {
 30			t.Fatalf("Create() error = %v", err)
 31		}
 32	
 33		manifestPath := filepath.Join(workDir, ".ddx", reviewSessionsDirName, session.ID, reviewManifestName)
 34		data, err := os.ReadFile(manifestPath)
 35		if err != nil {
 36			t.Fatalf("reading manifest.json: %v", err)
 37		}
 38		var got reviewSessionManifest
 39		if err := json.Unmarshal(data, &got); err != nil {
 40			t.Fatalf("parsing manifest.json: %v", err)
 41		}
 42	
 43		want := reviewSessionManifestFrom(session)
 44		if !reflect.DeepEqual(got, want) {
 45			t.Fatalf("manifest.json = %+v, want %+v", got, want)
 46		}
 47	}
