 50		workDir := t.TempDir()
 51		store := NewReviewSessionStore(workDir)
 52		sessionID := "review-append-001"
 53		if err := store.Create(ReviewSession{ID: sessionID, Status: "open"}); err != nil {
 54			t.Fatalf("Create() error = %v", err)
 55		}
 56	
 57		turn := ReviewTurn{
 58			Actor:     "reviewer",
 59			Content:   "looks good",
 60			CostUSD:   0.12,
 61			CreatedAt: time.Date(2026, 5, 5, 6, 0, 0, 0, time.UTC),
 62		}
 63		if err := store.AppendTurn(sessionID, turn); err != nil {
 64			t.Fatalf("AppendTurn() error = %v", err)
 65		}
 66	
 67		turnsPath := filepath.Join(workDir, ".ddx", reviewSessionsDirName, sessionID, reviewTurnsName)
 68		data, err := os.ReadFile(turnsPath)
 69		if err != nil {
 70			t.Fatalf("reading turns.jsonl: %v", err)
 71		}
 72		lines := splitNonEmptyLines(string(data))
 73		if len(lines) != 1 {
 74			t.Fatalf("turns.jsonl line count = %d, want 1", len(lines))
 75		}
 76		var got ReviewTurn
 77		if err := json.Unmarshal([]byte(lines[0]), &got); err != nil {
 78			t.Fatalf("parsing turns.jsonl: %v", err)
 79		}
 80		if !reflect.DeepEqual(got, turn) {
 81			t.Fatalf("turn = %+v, want %+v", got, turn)
 82		}
 83	}
