134	func splitNonEmptyLines(s string) []string {
135		lines := make([]string, 0)
136		for _, line := range strings.Split(s, "\n") {
137			if strings.TrimSpace(line) == "" {
138				continue
139			}
140			lines = append(lines, line)
141		}
142		return lines
143	}
